// // This is a 2-to-1 multiplexer that selects between inputs 'a' and 'b' based on the 'sel' signal. When 'sel' is 0, the output 'out' reflects the value of 'a'. When 'sel' is 1, 'out' takes the value of 'b'.
module top_module(a, b, sel, out);input a, b, sel;
output reg out; // Change output to reg to allow assignment in always block

   always @ (*)
   begin
      if (sel == 0)
         out = a;
      else
         out = b;
   end

endmodule
